+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = image ? start + 1 : start;
+  if (text[labelStart] !== '[' || (labelStart > 0 && text[labelStart - 1] === '!')) {
+    return null;
+  }
+
+  const labelEnd = findBalancedEnd(text, labelStart, '[', ']');
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const destinationEnd = findBalancedEnd(text, labelEnd + 1, '(', ')');
+  if (destinationEnd === -1) {
+    return null;
+  }
+
+  const rawLabel = text.slice(labelStart + 1, labelEnd);
+  const rawDestination = text.slice(labelEnd + 2, destinationEnd);
+  if (rawLabel.includes('\
') || rawDestination.includes('\
')) {
+    return null;
+  }
+  const target = parseDestination(rawDestination);
+  if (target === null) {
+    return null;
+  }
+  return {end: destinationEnd + 1, image, label: unescapeMarkdown(rawLabel), target};
+}
+
+function findBalancedEnd(text: string, start: number, opening: string, closing: string): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '\
') {
+      return -1;
+    }
+    if (text[index] === opening) {
+      depth++;
+    } else if (text[index] === closing && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(rawDestination: string): string | null {
+  const value = rawDestination.trim();
+  if (value.length === 0) {
+    return null;
+  }
+  if (value[0] === '<') {
+    let end = -1;
+    for (let index = 1; index < value.length; index++) {
+      if (value[index] === '\\\') {
+        index++;
+      } else if (value[index] === '>') {
+        end = index;
+        break;
+      }
+    }
+    if (end === -1 || value.slice(end + 1).trim() !== '') {
+      return null;
+    }
+    return unescapeMarkdown(value.slice(1, end));
+  }
+  if (hasUnescapedWhitespace(value)) {
+    return null;
+  }
+  return unescapeMarkdown(value);
+}
+
+function hasUnescapedWhitespace(value: string): boolean {
+  for (let index = 0; index < value.length; index++) {
+    if (value[index] === '\\\') {
+      index++;
+    } else if (/\\s/.test(value[index])) {
+      return true;
+    }
+  }
+  return false;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page.length === 0 ? heading : `${page} > ${heading}`;
+}
+
+function isEmbedSize(display: string): boolean {
+  return /^\\d+(?:x\\d+)?$/.test(display);
+}
+
+function markdownDestination(target: string): string {
+  return /\\s/.test(target) ? `<${target}>` : target;
